INSERT INTO `Clauses` (`GroupID`, `AuthorID`, `EditorID`, `Partition`, `Title`, `IsProtected`, `IsXML`, `IsDOM`, `Text`, `IsPublish`) VALUES
(4,100,100,'Contracts/PartnersProgram/Content','Регламент партнерской программы','yes','yes','yes','<NOBODY>\n <P>\n Данная партнёрская программа действует с 1 марта 2026 года и относится к клиентам привлечённым после этой даты.\n</P>\n <P>\n Начисления по клиентам зарегистрированным до этой даты, составляют 5% за услуги хостинга, виртуальных и выделенных серверов, 1% за услуги регистрации доменов и 0% за всё прочие услуги.\n</P>\n <P>\n Если клиент зарегистрирован после 1 марта, а дата создания заказа до этой даты (например, если заказ был перемещён со старого аккаунта на новый), действуют старые правила начисления.\n</P>\n <H2>\n Процент отчислений с заказов\n</H2>\n <COMP path=\"Clauses/PartnersRewardByService\" args=\"NotUsed\">\n [список тарифов]\n</COMP>\n <H2>\n Правила программы\n</H2>\n <UL class=\"Standard\">\n  <LI>Каждый клиент, имеющий учётную запись в нашем биллинге, может участвовать в партнёрской программе (необходимую информацию вы можете найти в разделе &quot;<A href=\"/v2/profile/DependUsers\">Партнёрская программа</A>&quot;).\n </LI>\n  <LI>Для начислений необходим договор с типом &quot;<A href=\"/v2/Contracts?section=Contracts\">Партнёрская программа</A>&quot;. При отсутствии договора, начисления не производятся, также не будут начислены суммы предшествующие созданию договора\n </LI>\n  <LI>Выплаты производятся за фактически оказанные услуги. т.е. если ваш реферал оплатил на год, всю сумму выплат вы получите в течении года. Если он откажется от услуги с возвратом средств - начисления по этой услуге будут прекращены. При смене клиентом тарифа на больший/меньший - соответственно изменится и сумма выплат вам.\n </LI>\n  <LI>Начисления производятся пятого числа каждого месяца за услуги, оказанные вашим рефералам в прошедшем месяце.\n </LI>\n  <LI>Обращаем ваше внимание, что если реферал просто положит средства на свой счёт в системе, не оплатив на них никаких заказов, то начислений партнёру за эти средства не будет, т.к. не было оказано никаких услуг.\n </LI>\n  <LI>Средства начисленные на партнёрский договор можно использоать для оплаты наших услуг, путём перевода с партнёрского договора на обычный, на котором находятся ваши услуги (Кнопка &quot;<A href=\"/v2/Contracts?section=Contracts\">Перевод средств</A>&quot;, в правом верхнем углу экрана)\n </LI>\n  <LI>Вывод денежных средств может быть произведен не чаще 1 раза в календарный месяц. Минимальная сумма для вывода - 10000 рублей.\n </LI>\n </UL>\n <H2>\n Запрещается\n</H2>\n <UL class=\"Standard\">\n  <LI>размещать гипертекстовые ссылки на наш сайт в любого вида сообщениях, независимо от их содержания и формы, рассылаемых по электронной почте или иными способами, с любых адресов (СПАМ)\n </LI>\n  <LI>перенаправлять посетителя на наш сайт без желания посетителя и его активных действий (редирект и т.п.)\n </LI>\n  <LI>размещать ссылки на наш сайт на web-ресурсах, которые нарушают законодательство РФ.\n </LI>\n </UL>\n <H2>\n Условия прекращения действия партнёрской программы и выплат\n</H2>\n <UL class=\"Standard\">\n  <LI style=\"border-bottom:1px dashed #DCDCDC;\">Отсутствие входа вами в нашу биллинговую систему, в течении года и более\n </LI>\n  <LI style=\"border-bottom:1px dashed #DCDCDC;\">Если в течении года и более, у вас не было новых рефералов оплативших наши услуги\n </LI>\n </UL>\n <P>\n В описанных выше случаях, привлечённые клиенты перестают быть вашими рефералами. Восстановление их в этом качестве - невозможно.\n</P>\n</NOBODY>\n','yes');
